    #[test]
    fn layer_kinds_support_magnitude_direction_agrees_with_distinct_cells_pattern_match() {
        // Parity against a hand-rolled `distinct_cells` pattern match:
        // read the support cardinality and classify by the same three-
        // way `if` chain the class-side projection folds into (Low on
        // support `<= 1`, High on support `+ 1 >= axis_cardinality`,
        // StrictInterior on the strict interior). Catches any future
        // drift where either implementation stops projecting through
        // the same `distinct_cells` primitive. Peer of the tier / diff
        // altitude peers on the same row.
        for chain in recessive_layer_kind_fixtures() {
            let slice = chain.as_slice();
            let via_seam = slice.layer_kinds_support_magnitude_direction();
            let hist = slice.layer_kind_histogram();
            let support = hist.distinct_cells();
            let cardinality = crate::axis_cardinality::<ConfigSourceKind>();
            let hand_rolled = if support <= 1 {
                crate::SupportMagnitudeDirection::Low
            } else if support + 1 >= cardinality {
                crate::SupportMagnitudeDirection::High
            } else {
                crate::SupportMagnitudeDirection::StrictInterior
            };
            assert_eq!(via_seam, hand_rolled);
        }
    }

    #[test]
    fn layer_kinds_support_magnitude_direction_cardinality_3_axis_never_reaches_strict_interior() {
        // **Cardinality-`3` strict-interior vacuous-unreachability
        // signature pin** ŌĆö the direct mirror of the cardinality-`3`
        // diff-altitude signature pin and of the sibling
        // `layer_kinds_support_boundary_distance_cardinality_3_axis_never_reaches_strict_interior`
        // on the same shared middle leg. On the three-cell
        // ConfigSourceKind axis, the `StrictInterior` bucket is
        // **vacuously unreachable**: the underlying strict-partial-
        // cover corner is itself vacuous (the strict interval `[2,
        // cardinality - 2] = [2, 1]` is empty), so no chain over
        // ConfigSourceKind can inhabit it. Structural signature of the
        // chain layer-kind sub-axis in the 5-column grid to be closed
        // on this projection ŌĆö the direct dual of the cardinality-`4`
        // tier-altitude signature pin
        // `tiers_support_magnitude_direction_cardinality_4_axis_reaches_strict_interior_variant`.
        // Covers every fixture in the reused set; a future refactor
        // that accidentally routes a cardinality-`3` chain to the
        // strict-interior bucket fails visibly.
        for chain in recessive_layer_kind_fixtures() {
            let slice = chain.as_slice();
            assert_ne!(
                slice.layer_kinds_support_magnitude_direction(),
                crate::SupportMagnitudeDirection::StrictInterior,
                "cardinality-3 ConfigSourceKind axis has vacuous strict \
                 interior ŌĆö no chain must land on the StrictInterior \
                 bucket",
            );
        }
        // Also cover the empty-chain edge specifically.
        let empty: [ConfigSource; 0] = [];
        assert_ne!(
            empty.layer_kinds_support_magnitude_direction(),
            crate::SupportMagnitudeDirection::StrictInterior,
        );
    }

    #[test]
    fn layer_kinds_support_magnitude_direction_cardinality_3_axis_two_bucket_profile_transposes_sibling_boundary_distance_pointwise()
     {
        // **Cardinality-`3` two-bucket transposed-profile pin** ŌĆö the
        // classifier only inhabits `{Low, High}` on the cardinality-`3`
        // layer-kind sub-axis (the `StrictInterior` middle leg is
        // vacuous), transposed mirror of the sibling
        // `layer_kinds_support_boundary_distance`'s `{Boundary,
        // Singular}` degeneracy on the same axis under the orthogonal-
        // axis fold of the four non-interior corners. Pointwise pin
        // that the boundary-vs-singular split and the low-vs-high split
        // pick different two-cell partitions of the same four non-
        // interior corners: the boundary bucket unions `{Empty,
        // FullCover}` while the low bucket unions `{Empty,
        // SingularSupport}`; the singular bucket unions
        // `{SingularSupport, SingularGap}` while the high bucket unions
        // `{SingularGap, FullCover}`. Structural pin of the
        // orthogonality of the two ternary partitions on the four non-
        // interior corners at every consumer site that reaches for
        // either two-bucket profile on the cardinality-`3` axis.
        for chain in recessive_layer_kind_fixtures() {
            let slice = chain.as_slice();
            let mag = slice.layer_kinds_support_magnitude_direction();
            assert!(
                matches!(
                    mag,
                    crate::SupportMagnitudeDirection::Low | crate::SupportMagnitudeDirection::High
                ),
                "cardinality-3 axis must inhabit only Low or High \
                 (bucket={mag:?})",
            );
            let bnd = slice.layer_kinds_support_boundary_distance();
            assert!(
                matches!(
                    bnd,
                    crate::SupportBoundaryDistance::Boundary
                        | crate::SupportBoundaryDistance::Singular
                ),
                "cardinality-3 axis must inhabit only Boundary or \
                 Singular (bucket={bnd:?})",
            );
            // Transposition on the four non-interior corners of the
            // cardinality-`3` axis:
            //   Empty           ŌåÆ (Boundary, Low)
            //   SingularSupport ŌåÆ (Singular, Low)
            //   SingularGap     ŌåÆ (Singular, High)
            //   FullCover       ŌåÆ (Boundary, High)
            // The two orthogonal ternary partitions pick *different*
            // two-cell splits of the four non-interior corners:
            // `{Empty, FullCover}` vs `{Empty, SingularSupport}`. The
            // diagnostic identity `mag.is_low() == bnd.is_boundary()`
            // holds exactly on the Empty and SingularGap corners
            // (where both classifiers agree on their respective
            // buckets), and fails on the SingularSupport and
            // FullCover corners (where the two orthogonal partitions
            // separate). Concrete pin of the orthogonal-axis split
            // that the shared-middle-leg pin does not surface on the
            // vacuous-strict-interior cardinality-`3` axis.
            assert_eq!(
                mag.is_low() == bnd.is_boundary(),
                !slice.layer_kinds_any_observed() || slice.layer_kinds_singular_gap(),
                "on the cardinality-3 axis, `is_low == is_boundary` \
                 coincides exactly on the Empty and SingularGap \
                 corners of the orthogonal transposition",
            );
        }
    }

    // ---- ConfigSourceChain::file_format_spread ŌĆö scalar-dispersion peer
    //      on the file-format sub-axis of the chain altitude, fusing
    //      peak_file_format_count and trough_file_format_count into one
