        let chain = vec![
            ConfigSource::Env("APP_".to_owned()),
            ConfigSource::Env("TOBIRA_".to_owned()),
        ];
        let slice = chain.as_slice();
        assert_eq!(slice.present_env_prefix_kinds().len(), 1);
